import{_ as p,c as a,o as e,ag as s}from"./chunks/framework.ELrfyV9R.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-18-wx-qclaw.md","filePath":"ai/2026-03/2026-03-18-wx-qclaw.md","lastUpdated":1774354925000}'),r={name:"ai/2026-03/2026-03-18-wx-qclaw.md"};function o(g,t,l,n,c,i){return e(),a("div",null,t[0]||(t[0]=[s('<p>拿到腾讯QClaw内测资格邀请码，我接入微信后的初体验分享</p><p>1、一键下载安装，输入邀请码，就可以扫码关联微信，进行聊天</p><p>2、邀请码只能用一次</p><p>3、聊天入口有点深，客服消息中的一个QClaw客服，与其他IM的Bot相比有点弱鸡了</p><p>4、客户端明明可以直接聊天，非要禁用了，让你在微信中用QClaw客服聊天</p><p>5、自定义大模型当然只能选择国内的模型厂商</p><p>6、目前这个QClaw同时只能关联一个Bot客服，但是你可以断开关联，使用另外一个微信扫码进行再次关联使用</p><p>7、目前聊天信息仅支持文字，至于群聊感觉一时半会有点难</p><p>8、让他开发了个CRM网页系统，可以自动使用浏览器打开预览网页</p><p>9、开发这个网页花了0.85元，我为啥不用免费的呢</p><p>10、极客们有人逆向成功接入OpenClaw了吗？</p><p>11、又浪费时间了，发完帖子准备卸载了</p><p>最后目前还可以申请邀请码,网址在最后一张图中，下载客户端后，第一张图中可以看到申请入口</p><p>最后目前还可以申请邀请码，</p><p>自定义模型只能选择国内大模型厂商</p><p>继 OpenClaw 之后，腾讯版的龙虾 ![🦞](<a href="https://abs-0.twimg.com/emoji/v2/svg/1f99e" target="_blank" rel="noreferrer">https://abs-0.twimg.com/emoji/v2/svg/1f99e</a>.</p><p>下午收到了 QClaw 邀请码 【腾讯科技】您的QClaw内测资格已审核通过，邀请码：3XXXKYOU。请前往 <a href="http://claw.guanjia.qq.com/" target="_blank" rel="noreferrer">http://claw.guanjia.qq.com</a> 激活使用。</p><p>下载体验了一下，客户端形式，下载安装，傻瓜化操作，非常方便。</p><p>跟龙虾的对话是在微信的 客服消息 里，折叠得太深了。 这个定位，充其量也就是一个客服，无法作为分身，被社交生态拦在了外面。 虽然入口在微信，但能做的事跟微信没啥关系。 有点鸡肋，期待群聊功能。</p><p>可能是因为当前还处在内测期间，功能比较少，期待后续更开放，哈哈</p><p>我问了一下，能拉个群吗？ 回答让我换其他 IM ，哈哈哈</p><p>--- 主人，我当前通过微信通道（wechat-access）跟你聊天，这个通道的能力比较有限，<strong>没有创建群聊的功能</strong>。</p><p>不过你有其他通道可以用：</p><p>| 平台 | 能否拉群 | |------|----------| | <strong>Telegram</strong> | <img src="https://abs-0.twimg.com/emoji/v2/svg/2705.svg" alt="✅" title="白重加粗勾选标记"> 可以（有多个 bot 账号） | | <strong>飞书</strong> | <img src="https://abs-0.twimg.com/emoji/v2/svg/2705.svg" alt="✅" title="白重加粗勾选标记"> 可以 | | <strong>企业微信</strong> | <img src="https://abs-0.twimg.com/emoji/v2/svg/26a0.svg" alt="⚠️" title="警告标志"> 需要确认 |</p><p>如果你想拉群，建议： 1. <strong>Telegram 群</strong> — 用 Telegram bot 更方便，支持各种自定义命令 2. <strong>飞书群</strong> — 如果你们团队用飞书</p><p>主人想在哪个平台拉群？告诉我具体需求（拉谁、群名等），我来帮你操作！</p>',26)]))}const w=p(r,[["render",o]]);export{_ as __pageData,w as default};
